def solve(arg1: dict) -> dict:
    users = {}
    reports = {}

    action = arg1.get('action')

    if action == 'createUser':
        username = arg1.get('username')
        email = arg1.get('email')
        password = arg1.get('password')

        if email in users:
            return {'status': 'error', 'message': 'Email already in use'}

        userId = '12345'  # Simulating user ID generation
        users[email] = {'username': username, 'email': email, 'password': password, 'userId': userId}
        return {'status': 'success', 'message': 'User created successfully', 'userId': userId}

    elif action == 'getUser':
        email = arg1.get('email')

        if email not in users:
            return {'status': 'error', 'message': 'User not found'}

        user = users[email]
        return {'username': user['username'], 'email': user['email']}

    elif action == 'downloadReport':
        reportId = arg1.get('reportId')

        if reportId not in reports:
            return {'status': 'error', 'message': 'Report not found'}

        reportData = reports[reportId]
        return {'status': 'success', 'message': 'Report downloaded successfully', 'reportData': reportData}

    return None
